  5→//! Parade command - Display comprehensive Heat status for project review
  6→//!
  7→//! Implements both heat view (Firemark) and pace view (Coronet).
  8→
  9→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 10→use crate::jjrf_favor::jjrf_Coronet as Coronet;
 11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_Heat as Heat, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
 12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
 13→use crate::jjrq_query::{jjrq_files_for_pace, jjrq_file_touches_for_heat, zjjrq_files_for_commit, zjjrq_bare_filename, zjjrq_is_infra_file};
 14→use crate::jjrs_steeplechase::{jjrs_ReinArgs, jjrs_get_entries, jjrs_SteeplechaseEntry};
 15→use std::collections::BTreeMap;
 16→use std::fmt::Write;
 17→use std::fs;
 18→
 19→/// Arguments for jjx_show command
 20→#[derive(clap::Args, Debug)]
 21→pub struct jjrpd_ParadeArgs {
 22→    /// Path to the Gallops JSON file
 23→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 24→    pub file: std::path::PathBuf,
 25→
 26→    /// Target: Firemark (heat view) or Coronet (pace view). If omitted, uses first racing heat.
 27→    pub target: Option<String>,
 28→
 29→    /// Show paddock and full dockets (heat mode only)
 30→    #[arg(long)]
 31→    pub detail: bool,
 32→
 33→    /// Show only remaining paces (exclude complete/abandoned)
 34→    #[arg(long)]
 35→    pub remaining: bool,
 36→}
 37→
 38→/// Run the show command - display comprehensive Heat status
 39→pub fn jjrpd_run_parade(args: jjrpd_ParadeArgs) -> i32 {
 40→    let gallops = match Gallops::jjrg_load(&args.file) {
 41→        Ok(g) => g,
 42→        Err(e) => {
 43→            eprintln!("jjx_show: error: {}", e);
 44→            return 1;
 45→        }
 46→    };
 47→
 48→    // Resolve target: use provided value or auto-select first racing heat
 49→    let target = match args.target {
 50→        Some(t) => t,
 51→        None => {
 52→            // Load gallops to resolve default heat
 53→            match zjjrpd_resolve_default_heat(&gallops) {
 54→                Ok(fm) => fm,
 55→                Err(e) => {
 56→                    eprintln!("jjx_show: error: {}", e);
 57→                    return 1;
 58→                }
 59→            }
 60→        }
 61→    };
 62→
 63→    // Determine target type by length
 64→    let target_str = target.strip_prefix('₢').or_else(|| target.strip_prefix('₣')).unwrap_or(&target);
 65→
 66→    if target_str.len() == 5 {
 67→        // Coronet - pace view
 68→        let coronet = match Coronet::jjrf_parse(&target) {
 69→            Ok(c) => c,
 70→            Err(e) => {
 71→                eprintln!("jjx_show: error: {}", e);
 72→                return 1;
 73→            }
 74→        };
 75→
 76→        // Extract parent firemark
 77→        let firemark = coronet.jjrf_parent_firemark();
 78→        let heat_key = firemark.jjrf_display();
 79→        let heat = match gallops.heats.get(&heat_key) {
 80→            Some(h) => h,
 81→            None => {
 82→                eprintln!("jjx_show: error: Heat '{}' not found", heat_key);
 83→                return 1;
 84→            }
 85→        };
 86→
 87→        // Find pace
 88→        let coronet_key = coronet.jjrf_display();
 89→        let pace = match heat.paces.get(&coronet_key) {
 90→            Some(p) => p,
 91→            None => {
 92→                eprintln!("jjx_show: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
 93→                return 1;
 94→            }
 95→        };
 96→
 97→        // Display pace view
 98→        if !pace.tacks.is_empty() {
 99→            // Print header with current state from tacks[0]
100→            let current_tack = &pace.tacks[0];
101→            println!("Pace: {} ({}) [{}]", current_tack.silks, coronet_key, zjjrpd_pace_state_str(&current_tack.state));
102→            println!("Heat: {}", heat_key);
103→
104→            // Show work files touched by this pace's commits
105→            match jjrq_files_for_pace(firemark.jjrf_as_str(), &coronet_key) {
106→                Ok(files) if !files.is_empty() => {
107→                    println!("Work files: {}", files.join(", "));
108→                }
109→                _ => {}
110→            }
111→            println!();
112→
113→            if args.detail {
114→                // Detail view: full tack history in reverse order (oldest first)
115→                for (index, tack) in pace.tacks.iter().rev().enumerate() {
116→                    let state_str = zjjrpd_pace_state_str(&tack.state);
117→                    let basis_str = if tack.basis == "0000000" {
118→                        "(no basis)".to_string()
119→                    } else {
120→                        tack.basis.clone()
121→                    };
122→
123→                    println!("[{}] {} (basis: {})", index, state_str, basis_str);
124→                    println!("    Silks: {}", tack.silks);
125→                    if let Some(ref direction) = tack.direction {
126→                        println!("    Warrant: {}", direction);
127→                    }
128→                    println!();
129→                    // Indent docket text
130→                    for line in tack.text.lines() {
131→                        println!("    {}", line);
132→                    }
133→                    println!();
134→                }
135→            } else {
136→                // Default view: latest tack docket only
137→                if let Some(ref direction) = current_tack.direction {
138→                    println!("Warrant: {}", direction);
139→                    println!();
140→                }
141→                for line in current_tack.text.lines() {
142→                    println!("{}", line);
143→                }
144→                println!();
145→            }
146→
147→            // Append files-per-commit bitmap
148→            zjjrpd_print_pace_commits(&firemark, &coronet_key);
149→        }
150→    } else if target_str.len() == 2 {
151→        // Firemark - heat view
152→        let firemark = match Firemark::jjrf_parse(&target) {
153→            Ok(fm) => fm,
154→            Err(e) => {
155→                eprintln!("jjx_show: error: {}", e);
156→                return 1;
157→            }
158→        };
159→
160→        let heat_key = firemark.jjrf_display();
161→        let heat = match gallops.heats.get(&heat_key) {
162→            Some(h) => h,
163→            None => {
164→                eprintln!("jjx_show: error: Heat '{}' not found", heat_key);
165→                return 1;
166→            }
167→        };
168→
169→        if args.detail {
170→            // Detail view: paddock + all dockets
171→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
172→                Ok(content) => content,
173→                Err(e) => {
174→                    eprintln!("jjx_show: error reading paddock file '{}': {}", heat.paddock_file, e);
175→                    return 1;
176→                }
177→            };
178→
179→            let status_str = match heat.status {
180→                HeatStatus::Racing => "racing",
181→                HeatStatus::Stabled => "stabled",
182→                HeatStatus::Retired => "retired",
183→            };
184→
185→            println!("Heat: {} ({})", heat.silks, heat_key);
186→            println!("Status: {}", status_str);
187→            println!("Created: {}", heat.creation_time);
188→            println!();
189→            println!("## Paddock");
190→            println!();
191→            println!("{}", paddock_content);
192→            println!();
193→            println!("## Paces");
194→            println!();
195→
196→            for coronet_key in &heat.order {
197→                if let Some(pace) = heat.paces.get(coronet_key) {
198→                    if let Some(tack) = pace.tacks.first() {
199→                        // Skip complete/abandoned if --remaining
200→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
201→                            continue;
202→                        }
203→                        let state_str = zjjrpd_pace_state_str(&tack.state);
204→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
205→                        println!();
206→                        println!("{}", tack.text);
207→                        if let Some(ref direction) = tack.direction {
208→                            println!();
209→                            println!("**Warrant:** {}", direction);
210→                        }
211→                        println!();
212→                    }
213→                }
214→            }
215→        } else {
216→            // List view: numbered paces
217→            // If --remaining, output markdown format
218→            if args.remaining {
219→                let mut complete_count = 0;
220→                let mut abandoned_count = 0;
221→                let mut rough_count = 0;
222→                let mut bridled_count = 0;
223→                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
224→                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
225→
226→                for coronet_key in &heat.order {
227→                    if let Some(pace) = heat.paces.get(coronet_key) {
228→                        if let Some(tack) = pace.tacks.first() {
229→                            match tack.state {
230→                                PaceState::Complete => complete_count += 1,
231→                                PaceState::Abandoned => abandoned_count += 1,
232→                                PaceState::Rough => {
233→                                    rough_count += 1;
234→                                    remaining_paces.push((coronet_key, pace));
235→                                    if first_remaining_pace.is_none() {
236→                                        first_remaining_pace = Some((coronet_key, pace));
237→                                    }
238→                                }
239→                                PaceState::Bridled => {
240→                                    bridled_count += 1;
241→                                    remaining_paces.push((coronet_key, pace));
242→                                    if first_remaining_pace.is_none() {
243→                                        first_remaining_pace = Some((coronet_key, pace));
244→                                    }
245→                                }
246→                            }
247→                        }
248→                    }
249→                }
250→
251→                let status_str = match heat.status {
252→                    HeatStatus::Racing => "racing",
253→                    HeatStatus::Stabled => "stabled",
254→                    HeatStatus::Retired => "retired",
255→                };
256→
257→                let remaining_count = rough_count + bridled_count;
258→
259→                // Header line with heat info
260→                println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
261→                println!("Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
262→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
263→                println!();
264→
265→                // Table with remaining paces
266→                if !remaining_paces.is_empty() {
267→                    // Set up table with column definitions
268→                    let mut table = jjrp_Table::jjrp_new(vec![
269→                        jjrp_Column::new("No", jjrp_Align::Right),
270→                        jjrp_Column::new("State", jjrp_Align::Left),
271→                        jjrp_Column::new("Pace", jjrp_Align::Left),
272→                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
273→                    ]);
274→
275→                    // Measure all rows to compute column widths
276→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
277→                        if let Some(tack) = pace.tacks.first() {
278→                            let state_str = zjjrpd_pace_state_str(&tack.state);
279→                            table.jjrp_measure(&[
280→                                &(idx + 1).to_string(),
281→                                state_str,
282→                                &tack.silks,
283→                                coronet_key,
284→                            ]);
285→                        }
286→                    }
287→
288→                    // Print header and separator
289→                    table.jjrp_print_header();
290→                    table.jjrp_print_separator();
291→
292→                    // Print data rows
293→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
294→                        if let Some(tack) = pace.tacks.first() {
295→                            let state_str = zjjrpd_pace_state_str(&tack.state);
296→                            table.jjrp_print_row(&[
297→                                &(idx + 1).to_string(),
298→                                state_str,
299→                                &tack.silks,
300→                                coronet_key,
301→                            ]);
302→                        }
303→                    }
304→                    println!();
305→                }
306→
307→                // Next up callout
308→                if let Some((coronet_key, pace)) = first_remaining_pace {
309→                    if let Some(tack) = pace.tacks.first() {
310→                        let state_str = zjjrpd_pace_state_str(&tack.state);
311→                        println!("Next: {} ({}) [{}]", tack.silks, coronet_key, state_str);
312→                        eprintln!();
313→                        eprintln!("Recommended: /jjc-heat-mount {}", heat_key);
314→                    }
315→                }
316→            } else {
317→                // Column-justified list view (all paces)
318→                // Set up table with column definitions
319→                let mut table = jjrp_Table::jjrp_new(vec![
320→                    jjrp_Column::new("No", jjrp_Align::Right),
321→                    jjrp_Column::new("State", jjrp_Align::Left),
322→                    jjrp_Column::new("Pace", jjrp_Align::Left),
323→                    jjrp_Column::new("₢Coronet", jjrp_Align::Left),
324→                ]);
325→
326→                // Measure all rows to compute column widths
327→                let mut num = 0;
328→                for coronet_key in &heat.order {
329→                    if let Some(pace) = heat.paces.get(coronet_key) {
330→                        if let Some(tack) = pace.tacks.first() {
331→                            num += 1;
332→                            let state_str = zjjrpd_pace_state_str(&tack.state);
333→                            table.jjrp_measure(&[
334→                                &num.to_string(),
335→                                state_str,
336→                                &tack.silks,
337→                                coronet_key,
338→                            ]);
339→                        }
340→                    }
341→                }
342→
343→                // Print header and separator
344→                table.jjrp_print_header();
345→                table.jjrp_print_separator();
346→
347→                // Print data rows
348→                let mut num = 0;
349→                for coronet_key in &heat.order {
350→                    if let Some(pace) = heat.paces.get(coronet_key) {
351→                        if let Some(tack) = pace.tacks.first() {
352→                            num += 1;
353→                            let state_str = zjjrpd_pace_state_str(&tack.state);
354→                            table.jjrp_print_row(&[
355→                                &num.to_string(),
356→                                state_str,
357→                                &tack.silks,
358→                                coronet_key,
359→                            ]);
360→                        }
361→                    }
362→                }
363→            }
364→        }
365→
366→        // Always show file-touch bitmap and commit swim lanes after pace listing
367→        jjrpd_print_file_bitmap(&firemark, heat);
368→        jjrpd_print_commit_swimlanes(&firemark, heat);
369→    } else {
370→        eprintln!("jjx_show: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", target_str.len());
371→        return 1;
372→    }
373→
374→    0
375→}
