377→/// Format the file-touch bitmap for a heat as a String.
378→///
379→/// Uses shared query routines from jjrq_query to get file touches,
380→/// then formats as a bitmap with columns per pace and rows per file,
381→/// grouped by identical touch patterns.
382→pub fn jjrpd_format_file_bitmap(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
383→    let touches = jjrq_file_touches_for_heat(firemark.jjrf_as_str())?;
384→
385→    // Build pace columns: only paces with commits, in heat order
386→    let mut pace_columns: Vec<(char, String, String)> = Vec::new();
387→    for coronet_key in &heat.order {
388→        if !touches.coronets_with_commits.contains(coronet_key) {
389→            continue;
390→        }
391→        if let Some(pace) = heat.paces.get(coronet_key) {
392→            if let Some(tack) = pace.tacks.first() {
393→                let raw = coronet_key.strip_prefix('₢').unwrap_or(coronet_key);
394→                if let Some(ch) = raw.chars().last() {
395→                    pace_columns.push((ch, coronet_key.clone(), tack.silks.clone()));
396→                }
397→            }
398→        }
399→    }
400→
401→    // Map coronet_display -> column index
402→    let mut coronet_to_col: BTreeMap<String, usize> = BTreeMap::new();
403→    for (idx, (_, coronet_display, _)) in pace_columns.iter().enumerate() {
404→        coronet_to_col.insert(coronet_display.clone(), idx);
405→    }
406→
407→    let total_cols = pace_columns.len();
408→
409→    // Build file -> touch vector from the shared query result
410→    let mut file_touches_map: BTreeMap<String, Vec<bool>> = BTreeMap::new();
411→
412→    for (coronet, files) in &touches.pace_files {
413→        if let Some(&col_idx) = coronet_to_col.get(coronet) {
414→            for filename in files {
415→                let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
416→                if col_idx < row.len() {
417→                    row[col_idx] = true;
418→                }
419→            }
420→        }
421→    }
422→
423→    let mut output = String::new();
424→
425→    if file_touches_map.is_empty() {
426→        writeln!(output, "File-touch bitmap: (no work file changes)").unwrap();
427→        return Ok(output);
428→    }
429→
430→    // Group files by identical touch pattern
431→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
432→    for (filename, pattern) in &file_touches_map {
433→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
434→    }
435→
436→    for files in pattern_groups.values_mut() {
437→        files.sort();
438→    }
439→
440→    // Header
441→    writeln!(output, "File-touch bitmap (x = pace commit touched file):").unwrap();
442→    writeln!(output).unwrap();
443→
444→    // Vertical legend
445→    for (i, (ch, _coronet, silks)) in pace_columns.iter().enumerate() {
446→        writeln!(output, "  {} {} {}", i + 1, ch, silks).unwrap();
447→    }
448→    writeln!(output).unwrap();
449→
450→    // Column header line (terminal chars aligned with bitmap positions)
451→    let header_chars: Vec<char> = pace_columns.iter().map(|(ch, _, _)| *ch).collect();
452→    let header_line: String = header_chars.iter().collect();
453→    writeln!(output, "{}", header_line).unwrap();
454→
455→    // Sort patterns: more touches first, then lexicographic
456→    let mut sorted_patterns: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
457→    sorted_patterns.sort_by(|(pat_a, _), (pat_b, _)| {
458→        let count_a: usize = pat_a.iter().filter(|&&b| b).count();
459→        let count_b: usize = pat_b.iter().filter(|&&b| b).count();
460→        count_b.cmp(&count_a).then_with(|| pat_a.cmp(pat_b))
461→    });
462→
463→    for (pattern, files) in &sorted_patterns {
464→        let bitmap: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
465→        writeln!(output, "{} {}", bitmap, files.join(", ")).unwrap();
466→    }
467→
468→    Ok(output)
469→}
470→
471→/// Print the file-touch bitmap for a heat to stdout.
472→pub(crate) fn jjrpd_print_file_bitmap(firemark: &Firemark, heat: &Heat) {
473→    match jjrpd_format_file_bitmap(firemark, heat) {
474→        Ok(output) => print!("{}", output),
475→        Err(e) => eprintln!("jjx_show: error getting file touches: {}", e),
476→    }
477→}
