479→/// Helper to convert PaceState to display string
480→pub(crate) fn zjjrpd_pace_state_str(state: &PaceState) -> &'static str {
481→    match state {
482→        PaceState::Rough => "rough",
483→        PaceState::Bridled => "bridled",
484→        PaceState::Complete => "complete",
485→        PaceState::Abandoned => "abandoned",
486→    }
487→}
