489→/// Resolve the default heat (first racing heat) when no target is specified
490→pub(crate) fn zjjrpd_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
491→    for (heat_key, heat) in &gallops.heats {
492→        if heat.status == HeatStatus::Racing {
493→            return Ok(heat_key.clone());
494→        }
495→    }
496→    Err("No racing heats found".to_string())
497→}
498→
499→/// Encode a column index as a dense character: 1-9 then a-z then A-Z (61 max)
500→fn zjjrpd_commit_index_char(index: usize) -> Option<char> {
501→    match index {
502→        0..=8 => Some((b'1' + index as u8) as char),
503→        9..=34 => Some((b'a' + (index - 9) as u8) as char),
504→        35..=60 => Some((b'A' + (index - 35) as u8) as char),
505→        _ => None,
506→    }
507→}
