617→/// Print files-per-commit bitmap for a single pace.
618→///
619→/// Shows which files each commit in this pace touched.
620→/// Called after tack history in pace parade.
621→fn zjjrpd_print_pace_commits(firemark: &Firemark, coronet_key: &str) {
622→    let rein_args = jjrs_ReinArgs {
623→        firemark: firemark.jjrf_as_str().to_string(),
624→        limit: 10000,
625→    };
626→
627→    let entries = match jjrs_get_entries(&rein_args) {
628→        Ok(e) => e,
629→        Err(e) => {
630→            eprintln!("jjx_show: error getting steeplechase entries: {}", e);
631→            return;
632→        }
633→    };
634→
635→    // Filter by coronet, then reverse for chronological order
636→    let pace_entries: Vec<&jjrs_SteeplechaseEntry> = entries
637→        .iter()
638→        .filter(|e| e.coronet.as_deref() == Some(coronet_key))
639→        .collect::<Vec<_>>()
640→        .into_iter()
641→        .rev()
642→        .collect();
643→
644→    if pace_entries.is_empty() {
645→        return;
646→    }
647→
648→    // Get files for each commit
649→    let num_commits = pace_entries.len();
650→    let mut file_touches: BTreeMap<String, Vec<bool>> = BTreeMap::new();
651→
652→    for (col, entry) in pace_entries.iter().enumerate() {
653→        let files = zjjrq_files_for_commit(&entry.commit);
654→        for path in files {
655→            if zjjrq_is_infra_file(&path) {
656→                continue;
657→            }
658→            let bare = zjjrq_bare_filename(&path);
659→            let row = file_touches.entry(bare).or_insert_with(|| vec![false; num_commits]);
660→            row[col] = true;
661→        }
662→    }
663→
664→    if file_touches.is_empty() {
665→        println!();
666→        println!("Pace commits: (no project file commits)");
667→        return;
668→    }
669→
670→    println!();
671→    println!("Pace commits (x = commit touched file):");
672→    println!();
673→
674→    // Legend: commit index char, SHA, subject
675→    for (i, entry) in pace_entries.iter().enumerate() {
676→        let ch = zjjrpd_commit_index_char(i).unwrap_or('?');
677→        println!("  {} {}  {}", ch, entry.commit, entry.subject);
678→    }
679→    println!();
680→
681→    // Column header line
682→    let header: String = (0..num_commits).filter_map(zjjrpd_commit_index_char).collect();
683→    println!("{}", header);
684→
685→    // Group by identical touch pattern
686→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
687→    for (filename, pattern) in &file_touches {
688→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
689→    }
690→    for files in pattern_groups.values_mut() {
691→        files.sort();
692→    }
693→
694→    // Sort: more touches first, then lexicographic
695→    let mut sorted: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
696→    sorted.sort_by(|(a, _), (b, _)| {
697→        let ca: usize = a.iter().filter(|&&v| v).count();
698→        let cb: usize = b.iter().filter(|&&v| v).count();
699→        cb.cmp(&ca).then_with(|| a.cmp(b))
700→    });
701→
702→    for (pattern, files) in &sorted {
703→        let bits: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
704→        println!("{} {}", bits, files.join(", "));
705→    }
706→}
