 66→fn jjrm_capture<F: FnOnce() -> i32>(f: F) -> Result<CallToolResult, McpError> {
 67→    use std::io::{Read, Write};
 68→    use std::os::unix::io::FromRawFd;
 69→
 70→    unsafe {
 71→        // SAFETY: pipe() returns two valid fds on success
 72→        let mut fds = [0i32; 2];
 73→        if libc::pipe(fds.as_mut_ptr()) != 0 {
 74→            return Err(McpError::internal_error("pipe creation failed", None));
 75→        }
 76→        let (read_fd, write_fd) = (fds[0], fds[1]);
 77→
 78→        // SAFETY: dup() returns a new fd pointing to the same stdout
 79→        let saved = libc::dup(libc::STDOUT_FILENO);
 80→        if saved < 0 {
 81→            libc::close(read_fd);
 82→            libc::close(write_fd);
 83→            return Err(McpError::internal_error("dup stdout failed", None));
 84→        }
 85→
 86→        // SAFETY: dup2 atomically redirects stdout to pipe write end
 87→        libc::dup2(write_fd, libc::STDOUT_FILENO);
 88→        libc::close(write_fd);
 89→
 90→        // Reader thread prevents pipe buffer deadlock
 91→        let reader_handle = std::thread::spawn(move || {
 92→            // SAFETY: read_fd is a valid fd from pipe(), transferred to this thread
 93→            let mut reader = std::fs::File::from_raw_fd(read_fd);
 94→            let mut output = String::new();
 95→            reader.read_to_string(&mut output).ok();
 96→            output
 97→        });
 98→
 99→        let code = f();
100→        std::io::stdout().flush().ok();
101→
102→        // SAFETY: restore original stdout, close our saved copy
103→        libc::dup2(saved, libc::STDOUT_FILENO);
104→        libc::close(saved);
105→
106→        let output = reader_handle.join().unwrap_or_default();
107→
108→        if code == 0 {
109→            Ok(CallToolResult::success(vec![Content::text(output)]))
110→        } else {
111→            Ok(CallToolResult::error(vec![Content::text(output)]))
112→        }
113→    }
114→}
