190→        jjrx_JjxCommands::Archive(args) => jjrrt_run_retire(args),
191→        jjrx_JjxCommands::Create(args) => jjrx_run_nominate(args),
192→        jjrx_JjxCommands::Enroll(args) => {
193→            match jjrg_read_stdin() {
194→                Ok(docket) => jjrsl_run_slate(args, docket),
195→                Err(e) => { eprintln!("jjx_enroll: error: {}", e); 1 }
196→            }
197→        }
198→        jjrx_JjxCommands::Reorder(args) => jjrrl_run_rail(args),
